    92→	if block == nil {
    93→		return nil, errors.New("unable to decode manifest")
    94→	}
    95→
    96→	// Convert to a well typed object
    97→	var manifest PluginManifest
    98→	err := json.Unmarshal(block.Plaintext, &manifest)
    99→	if err != nil {
   100→		return nil, fmt.Errorf("%v: %w", "Error parsing manifest JSON", err)
   101→	}
